  1→import { spawn, execFileSync, type ChildProcess } from "node:child_process";
  2→import { Transform } from "node:stream";
  3→import fs from "node:fs";
  4→import path from "node:path";
  5→import { randomUUID } from "node:crypto";
  6→import { ClientSideConnection, ndJsonStream } from "@agentclientprotocol/sdk";
  7→import type {
  8→  Agent,
  9→  Client,
 10→  PromptResponse,
 11→  PermissionOption as SdkPermissionOption,
 12→} from "@agentclientprotocol/sdk";
 13→import { nodeToWebWritable, nodeToWebReadable } from "./streams.js";
 14→import { StderrCapture } from "./stderr-capture.js";
 15→import { TypedEmitter } from "./typed-emitter.js";
 16→import type {
 17→  AgentDefinition,
 18→  AgentEvent,
 19→  Attachment,
 20→  PermissionRequest,
 21→} from "./types.js";
 22→import { createChildLogger } from "./log.js";
 23→const log = createChildLogger({ module: "agent-instance" });
 24→
 25→/** Find the nearest ancestor directory containing package.json */
 26→function findPackageRoot(startDir: string): string {
 27→  let dir = startDir;
 28→  while (dir !== path.dirname(dir)) {
 29→    if (fs.existsSync(path.join(dir, "package.json"))) {
 30→      return dir;
 31→    }
 32→    dir = path.dirname(dir);
 33→  }
 34→  return startDir;
 35→}
 36→
 37→/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
 38→function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
 39→  // Directories to search for node_modules: cwd AND the package's own directory
 40→  const searchRoots = [process.cwd()];
 41→  // Add the directory where this package is installed (for global installs)
 42→  // Use findPackageRoot instead of hardcoded "../.." to handle both tsc (dist/core/)
 43→  // and tsup bundle (dist/) directory structures correctly
 44→  const ownDir = findPackageRoot(import.meta.dirname);
 45→  if (ownDir !== process.cwd()) {
 46→    searchRoots.push(ownDir);
 47→  }
 48→
 49→  // 1. Check node_modules for the package's actual JS entry point
 50→  for (const root of searchRoots) {
 51→    const packageDirs = [
 52→      path.resolve(root, "node_modules", "@zed-industries", cmd, "dist", "index.js"),
 53→      path.resolve(root, "node_modules", cmd, "dist", "index.js"),
 54→    ];
 55→    for (const jsPath of packageDirs) {
 56→      if (fs.existsSync(jsPath)) {
 57→        return { command: process.execPath, args: [jsPath] };
 58→      }
 59→    }
 60→  }
 61→
 62→  // 2. Check .bin — if it's a JS file with shebang, run with node directly
 63→  for (const root of searchRoots) {
 64→    const localBin = path.resolve(root, "node_modules", ".bin", cmd);
 65→    if (fs.existsSync(localBin)) {
 66→      const content = fs.readFileSync(localBin, "utf-8");
 67→      if (content.startsWith("#!/usr/bin/env node")) {
 68→        return { command: process.execPath, args: [localBin] };
 69→      }
 70→      // Shell wrapper — try to find the target JS file
 71→      const match = content.match(/"([^"]+\.js)"/);
 72→      if (match) {
 73→        const target = path.resolve(path.dirname(localBin), match[1]);
 74→        if (fs.existsSync(target)) {
 75→          return { command: process.execPath, args: [target] };
 76→        }
 77→      }
 78→    }
 79→  }
 80→
 81→  // 3. Try resolving from PATH using which
 82→  try {
 83→    const fullPath = execFileSync("which", [cmd], { encoding: "utf-8" }).trim();
 84→    if (fullPath) {
 85→      const content = fs.readFileSync(fullPath, "utf-8");
 86→      if (content.startsWith("#!/usr/bin/env node")) {
 87→        return { command: process.execPath, args: [fullPath] };
 88→      }
 89→    }
 90→  } catch {
 91→    // which failed
 92→  }
 93→
 94→  // 4. Fallback: use command as-is
 95→  return { command: cmd, args: [] };
 96→}
 97→
 98→interface TerminalState {
 99→  process: ChildProcess;
100→  output: string;
101→  exitStatus: { exitCode: number | null; signal: string | null } | null;
102→}
103→
104→export interface AgentInstanceEvents {
105→  agent_event: (event: AgentEvent) => void;
106→}
107→
108→export class AgentInstance extends TypedEmitter<AgentInstanceEvents> {
109→  private connection!: ClientSideConnection;
110→  private child!: ChildProcess;
111→  private stderrCapture!: StderrCapture;
112→  private terminals: Map<string, TerminalState> = new Map();
113→
114→  sessionId!: string;
115→  agentName: string;
116→  promptCapabilities?: { image?: boolean; audio?: boolean };
117→
118→  // Callback — set by core when wiring events
119→  onPermissionRequest: (request: PermissionRequest) => Promise<string> =
120→    async () => "";
121→
122→  private constructor(agentName: string) {
123→    super();
124→    this.agentName = agentName;
125→  }
126→
127→  private static async spawnSubprocess(
128→    agentDef: AgentDefinition,
129→    workingDirectory: string,
130→  ): Promise<AgentInstance> {
