144→      [...resolved.args, ...agentDef.args],
145→      {
146→        stdio: ["pipe", "pipe", "pipe"],
147→        cwd: workingDirectory,
148→        env: { ...process.env, ...agentDef.env },
149→      },
150→    );
151→
152→    await new Promise<void>((resolve, reject) => {
153→      instance.child.on("error", (err) => {
154→        reject(
155→          new Error(
156→            `Failed to spawn agent "${agentDef.name}": ${err.message}. Is "${agentDef.command}" installed?`,
157→          ),
158→        );
159→      });
160→      instance.child.on("spawn", () => resolve());
161→    });
162→
163→    instance.stderrCapture = new StderrCapture(50);
164→    instance.child.stderr!.on("data", (chunk: Buffer) => {
165→      instance.stderrCapture.append(chunk.toString());
166→    });
167→
168→    const stdinLogger = new Transform({
169→      transform(chunk, _enc, cb) {
170→        log.debug(
171→          { direction: "send", raw: chunk.toString().trimEnd() },
172→          "ACP raw",
173→        );
174→        cb(null, chunk);
175→      },
176→    });
177→    stdinLogger.pipe(instance.child.stdin!);
178→
179→    const stdoutLogger = new Transform({
180→      transform(chunk, _enc, cb) {
181→        log.debug(
182→          { direction: "recv", raw: chunk.toString().trimEnd() },
183→          "ACP raw",
184→        );
185→        cb(null, chunk);
186→      },
187→    });
188→    instance.child.stdout!.pipe(stdoutLogger);
189→
190→    const toAgent = nodeToWebWritable(stdinLogger);
191→    const fromAgent = nodeToWebReadable(stdoutLogger);
192→    const stream = ndJsonStream(toAgent, fromAgent);
193→
194→    instance.connection = new ClientSideConnection(
195→      (_agent: Agent): Client => instance.createClient(_agent),
196→      stream,
197→    );
