217→  private setupCrashDetection(): void {
218→    this.child.on("exit", (code, signal) => {
219→      log.info(
220→        { sessionId: this.sessionId, exitCode: code, signal },
221→        "Agent process exited",
222→      );
223→      if (code !== 0 && code !== null) {
224→        const stderr = this.stderrCapture.getLastLines();
225→        this.emit('agent_event', {
226→          type: "error",
227→          message: `Agent crashed (exit code ${code})\n${stderr}`,
228→        });
