248→      agentDef,
249→      workingDirectory,
250→    );
251→
252→    const response = await instance.connection.newSession({
253→      cwd: workingDirectory,
254→      mcpServers: [],
255→    });
256→    instance.sessionId = response.sessionId;
257→    instance.setupCrashDetection();
258→
