266→  static async resume(
267→    agentDef: AgentDefinition,
268→    workingDirectory: string,
269→    agentSessionId: string,
270→  ): Promise<AgentInstance> {
271→    log.debug({ agentName: agentDef.name, agentSessionId }, "Resuming agent");
272→    const spawnStart = Date.now();
273→
