309→  // createClient — implemented in Task 6b
310→  private createClient(_agent: Agent): Client {
311→    const self = this;
312→    const MAX_OUTPUT_BYTES = 1024 * 1024; // 1MB cap
313→
314→    return {
315→      // ── Session updates ──────────────────────────────────────────────────
316→      async sessionUpdate(params) {
317→        const update = params.update;
318→        let event: AgentEvent | null = null;
319→
320→        switch (update.sessionUpdate) {
321→          case "agent_message_chunk":
322→            if (update.content.type === "text") {
323→              event = { type: "text", content: update.content.text };
324→            } else if (update.content.type === "image") {
325→              // ACP SDK types don't expose data/mimeType fields for image content
326→              const c = update.content as unknown as { data: string; mimeType: string };
327→              event = { type: "image_content", data: c.data, mimeType: c.mimeType };
328→            } else if (update.content.type === "audio") {
329→              // ACP SDK types don't expose data/mimeType fields for audio content
330→              const c = update.content as unknown as { data: string; mimeType: string };
331→              event = { type: "audio_content", data: c.data, mimeType: c.mimeType };
332→            }
333→            break;
334→          case "agent_thought_chunk":
335→            if (update.content.type === "text") {
336→              event = { type: "thought", content: update.content.text };
337→            }
338→            break;
339→          case "tool_call":
340→            event = {
341→              type: "tool_call",
342→              id: update.toolCallId,
343→              name: update.title,
344→              kind: update.kind ?? undefined,
345→              status: update.status ?? "pending",
346→              content: update.content ?? undefined,
347→              rawInput: (update as any).rawInput ?? undefined,
348→              meta: (update as any)._meta ?? undefined,
349→            };
350→            break;
351→          case "tool_call_update":
352→            event = {
353→              type: "tool_update",
354→              id: update.toolCallId,
355→              name: update.title ?? undefined,
356→              kind: update.kind ?? undefined,
357→              status: update.status ?? "pending",
358→              content: update.content ?? undefined,
359→              rawInput: (update as any).rawInput ?? undefined,
360→              meta: (update as any)._meta ?? undefined,
361→            };
362→            break;
363→          case "plan":
364→            event = { type: "plan", entries: update.entries };
365→            break;
366→          case "usage_update":
367→            event = {
368→              type: "usage",
369→              tokensUsed: update.used,
370→              contextSize: update.size,
371→              cost: update.cost ?? undefined,
372→            };
373→            break;
374→          case "available_commands_update":
375→            event = {
376→              type: "commands_update",
377→              commands: update.availableCommands,
378→            };
379→            break;
380→          default:
381→            // Unknown update type — ignore
382→            return;
383→        }
384→
385→        if (event !== null) {
386→          self.emit('agent_event', event);
387→        }
388→      },
389→
390→      // ── Permission requests ──────────────────────────────────────────────
391→      async requestPermission(params) {
392→        const permissionRequest: PermissionRequest = {
393→          id: params.toolCall.toolCallId,
394→          description: params.toolCall.title ?? params.toolCall.toolCallId,
395→          options: params.options.map((opt: SdkPermissionOption) => ({
396→            id: opt.optionId,
397→            label: opt.name,
398→            isAllow: opt.kind === "allow_once" || opt.kind === "allow_always",
399→          })),
400→        };
401→
402→        const selectedOptionId =
403→          await self.onPermissionRequest(permissionRequest);
404→        return {
405→          outcome: { outcome: "selected" as const, optionId: selectedOptionId },
406→        };
407→      },
408→
409→      // ── File operations ──────────────────────────────────────────────────
410→      async readTextFile(params) {
411→        const content = await fs.promises.readFile(params.path, "utf-8");
412→        return { content };
413→      },
414→
415→      async writeTextFile(params) {
416→        await fs.promises.mkdir(path.dirname(params.path), { recursive: true });
417→        await fs.promises.writeFile(params.path, params.content, "utf-8");
418→        return {};
419→      },
420→
421→      // ── Terminal operations ──────────────────────────────────────────────
422→      async createTerminal(params) {
423→        const terminalId = randomUUID();
424→        const args = params.args ?? [];
425→        const env: Record<string, string> = {};
426→        for (const ev of params.env ?? []) {
427→          env[ev.name] = ev.value;
428→        }
429→
430→        const childProcess = spawn(params.command, args, {
431→          cwd: params.cwd ?? undefined,
432→          env: { ...process.env, ...env },
433→          shell: false,
434→        });
435→
436→        const state: TerminalState = {
437→          process: childProcess,
438→          output: "",
439→          exitStatus: null,
440→        };
441→        self.terminals.set(terminalId, state);
442→
443→        const outputByteLimit = params.outputByteLimit ?? MAX_OUTPUT_BYTES;
444→
445→        const appendOutput = (chunk: string) => {
446→          state.output += chunk;
447→          // Truncate from the beginning if over limit
448→          const bytes = Buffer.byteLength(state.output, "utf-8");
449→          if (bytes > outputByteLimit) {
450→            // Find truncation point at character boundary
451→            const excess = bytes - outputByteLimit;
452→            state.output = state.output.slice(excess);
453→          }
454→        };
455→
456→        childProcess.stdout?.on("data", (chunk: Buffer) =>
457→          appendOutput(chunk.toString()),
458→        );
459→        childProcess.stderr?.on("data", (chunk: Buffer) =>
460→          appendOutput(chunk.toString()),
461→        );
462→
463→        childProcess.on("exit", (code, signal) => {
464→          state.exitStatus = { exitCode: code, signal };
465→        });
466→
467→        return { terminalId };
468→      },
469→
470→      async terminalOutput(params) {
471→        const state = self.terminals.get(params.terminalId);
472→        if (!state) {
473→          throw new Error(`Terminal not found: ${params.terminalId}`);
474→        }
475→        return {
476→          output: state.output,
477→          truncated: false,
478→          exitStatus: state.exitStatus
479→            ? {
480→                exitCode: state.exitStatus.exitCode,
481→                signal: state.exitStatus.signal,
482→              }
483→            : undefined,
484→        };
485→      },
486→
487→      async waitForTerminalExit(params) {
488→        const state = self.terminals.get(params.terminalId);
489→        if (!state) {
490→          throw new Error(`Terminal not found: ${params.terminalId}`);
491→        }
492→        if (state.exitStatus !== null) {
493→          return {
494→            exitCode: state.exitStatus.exitCode,
495→            signal: state.exitStatus.signal,
496→          };
497→        }
498→        return new Promise((resolve) => {
499→          state.process.on("exit", (code, signal) => {
500→            resolve({ exitCode: code, signal });
501→          });
502→        });
503→      },
504→
505→      async killTerminal(params) {
506→        const state = self.terminals.get(params.terminalId);
507→        if (!state) {
508→          throw new Error(`Terminal not found: ${params.terminalId}`);
509→        }
510→        state.process.kill("SIGTERM");
511→        return {};
512→      },
513→
514→      async releaseTerminal(params) {
515→        const state = self.terminals.get(params.terminalId);
516→        if (!state) {
517→          return;
518→        }
519→        state.process.kill("SIGKILL");
520→        self.terminals.delete(params.terminalId);
521→      },
522→    };
523→  }
524→
525→  async prompt(text: string, attachments?: Attachment[]): Promise<PromptResponse> {
526→    const contentBlocks: Array<Record<string, unknown>> = [{ type: "text", text }];
527→
528→    // MIME types supported by Claude API for base64 image content
529→    const SUPPORTED_IMAGE_MIMES = new Set(["image/jpeg", "image/png", "image/gif", "image/webp"]);
530→
531→    for (const att of attachments ?? []) {
532→      const tooLarge = att.size > 10 * 1024 * 1024; // 10MB base64 guard
533→
534→      if (att.type === "image" && this.promptCapabilities?.image && !tooLarge && SUPPORTED_IMAGE_MIMES.has(att.mimeType)) {
535→        const data = await fs.promises.readFile(att.filePath);
536→        contentBlocks.push({ type: "image", data: data.toString("base64"), mimeType: att.mimeType });
537→      } else if (att.type === "audio" && this.promptCapabilities?.audio && !tooLarge) {
538→        const data = await fs.promises.readFile(att.filePath);
539→        contentBlocks.push({ type: "audio", data: data.toString("base64"), mimeType: att.mimeType });
540→      } else {
541→        // Fallback: append file path to text so agent can read from disk
542→        if ((att.type === "image" || att.type === "audio") && !tooLarge) {
543→          log.debug(
544→            { type: att.type, capabilities: this.promptCapabilities ?? {} },
545→            "Agent does not support %s content, falling back to file path",
546→            att.type,
547→          );
548→        }
549→        (contentBlocks[0] as { text: string }).text += `\n\n[Attached file: ${att.filePath}]`;
550→      }
551→    }
552→
553→    return this.connection.prompt({
554→      sessionId: this.sessionId,
555→      prompt: contentBlocks as any,
556→    });
557→  }
558→
559→  async cancel(): Promise<void> {
560→    await this.connection.cancel({ sessionId: this.sessionId });
561→  }
562→
563→  async destroy(): Promise<void> {
564→    // Cleanup terminals
565→    for (const [, t] of this.terminals) {
566→      t.process.kill("SIGKILL");
567→    }
568→    this.terminals.clear();
569→
570→    // Kill agent subprocess
571→    this.child.kill("SIGTERM");
572→    setTimeout(() => {
573→      if (!this.child.killed) this.child.kill("SIGKILL");
574→    }, 10_000);
575→  }
576→}
