224→      process.env.OPENACP_CONFIG_PATH || expandHome("~/.openacp/config.json");
225→  }
226→
227→  async load(): Promise<void> {
228→    // 1. Ensure directory exists
229→    const dir = path.dirname(this.configPath);
230→    fs.mkdirSync(dir, { recursive: true });
231→
232→    // 2. If config file doesn't exist, create default
233→    if (!fs.existsSync(this.configPath)) {
234→      fs.writeFileSync(
235→        this.configPath,
236→        JSON.stringify(DEFAULT_CONFIG, null, 2),
237→      );
238→      log.info({ configPath: this.configPath }, "Config created");
239→      log.info(
240→        "Please edit it with your channel credentials (Telegram bot token, Discord bot token, etc.), then restart.",
241→      );
242→      process.exit(1);
243→    }
244→
245→    // 3. Read and parse
246→    const raw = JSON.parse(fs.readFileSync(this.configPath, "utf-8"));
247→
248→    // 3.5. Auto-migrate config
249→    const { changed: configUpdated } = applyMigrations(raw);
250→    if (configUpdated) {
251→      fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2));
252→    }
253→
254→    // 4. Apply env var overrides
255→    this.applyEnvOverrides(raw);
256→
257→    // 5. Validate with Zod
258→    const result = ConfigSchema.safeParse(raw);
259→    if (!result.success) {
260→      log.error("Config validation failed");
261→      for (const issue of result.error.issues) {
262→        log.error(
263→          { path: issue.path.join("."), message: issue.message },
264→          "Validation error",
265→        );
266→      }
267→      process.exit(1);
268→    }
269→    this.config = result.data;
270→  }
271→
272→  get(): Config {
273→    return this.config;
274→  }
275→
276→  async save(
277→    updates: Record<string, unknown>,
278→    changePath?: string,
279→  ): Promise<void> {
280→    const oldConfig = this.config ? structuredClone(this.config) : undefined;
281→    // Read current file, merge updates, write back
282→    const raw = JSON.parse(fs.readFileSync(this.configPath, "utf-8"));
283→    this.deepMerge(raw, updates);
284→    fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2));
285→    // Re-validate and update in-memory config
286→    const result = ConfigSchema.safeParse(raw);
287→    if (result.success) {
288→      this.config = result.data;
289→    }
290→    // Emit change event if path provided
291→    if (changePath) {
292→      const { getConfigValue } = await import("./config-registry.js");
293→      const value = getConfigValue(this.config, changePath);
294→      const oldValue = oldConfig
295→        ? getConfigValue(oldConfig, changePath)
296→        : undefined;
