402→    }
403→    if (process.env.OPENACP_SPEECH_GROQ_API_KEY) {
404→      raw.speech = raw.speech || {};
405→      const speech = raw.speech as Record<string, unknown>;
406→      speech.stt = speech.stt || {};
407→      const stt = speech.stt as Record<string, unknown>;
408→      stt.providers = stt.providers || {};
409→      const providers = stt.providers as Record<string, unknown>;
410→      providers.groq = providers.groq || {};
411→      (providers.groq as Record<string, unknown>).apiKey =
412→        process.env.OPENACP_SPEECH_GROQ_API_KEY;
413→    }
