416→  private deepMerge(
417→    target: Record<string, unknown>,
418→    source: Record<string, unknown>,
419→  ): void {
420→    for (const key of Object.keys(source)) {
421→      const val = source[key];
422→      if (val && typeof val === "object" && !Array.isArray(val)) {
423→        if (!target[key]) target[key] = {};
424→        this.deepMerge(
425→          target[key] as Record<string, unknown>,
426→          val as Record<string, unknown>,
427→        );
428→      } else {
429→        target[key] = val;
430→      }
431→    }
432→  }
