 10→
 11→describe("escapeHtml", () => {
 12→  it("escapes ampersand", () => {
 13→    expect(escapeHtml("a & b")).toBe("a &amp; b");
 14→  });
 15→
 16→  it("escapes less-than", () => {
 17→    expect(escapeHtml("a < b")).toBe("a &lt; b");
 18→  });
 19→
 20→  it("escapes greater-than", () => {
 21→    expect(escapeHtml("a > b")).toBe("a &gt; b");
 22→  });
 23→
 24→  it("escapes all HTML entities together", () => {
 25→    expect(escapeHtml('<div class="test">&nbsp;</div>')).toBe(
 26→      '&lt;div class="test"&gt;&amp;nbsp;&lt;/div&gt;',
 27→    );
 28→  });
 29→
 30→  it("returns empty string for null", () => {
 31→    expect(escapeHtml(null)).toBe("");
 32→  });
 33→
 34→  it("returns empty string for undefined", () => {
 35→    expect(escapeHtml(undefined)).toBe("");
 36→  });
 37→
 38→  it("returns empty string for empty string", () => {
 39→    expect(escapeHtml("")).toBe("");
 40→  });
 41→
 42→  it("preserves text without HTML entities", () => {
 43→    expect(escapeHtml("hello world")).toBe("hello world");
 44→  });
 45→});
 46→
 47→describe("markdownToTelegramHtml", () => {
 48→  it("converts bold **text**", () => {
 49→    expect(markdownToTelegramHtml("**bold text**")).toBe("<b>bold text</b>");
 50→  });
 51→
 52→  it("converts italic *text*", () => {
 53→    expect(markdownToTelegramHtml("*italic*")).toBe("<i>italic</i>");
 54→  });
 55→
 56→  it("handles bold and italic together", () => {
 57→    const result = markdownToTelegramHtml("**bold** and *italic*");
 58→    expect(result).toBe("<b>bold</b> and <i>italic</i>");
 59→  });
 60→
 61→  it("converts inline code", () => {
 62→    const result = markdownToTelegramHtml("use `console.log`");
 63→    expect(result).toBe("use <code>console.log</code>");
 64→  });
 65→
 66→  it("converts fenced code blocks", () => {
 67→    const result = markdownToTelegramHtml("```js\nconst x = 1\n```");
 68→    expect(result).toContain('<pre><code class="language-js">');
 69→    expect(result).toContain("const x = 1");
 70→    expect(result).toContain("</code></pre>");
 71→  });
 72→
 73→  it("converts fenced code blocks without language", () => {
 74→    const result = markdownToTelegramHtml("```\nsome code\n```");
 75→    expect(result).toContain("<pre><code>");
 76→    expect(result).toContain("some code");
 77→  });
 78→
 79→  it("converts links [text](url)", () => {
 80→    const result = markdownToTelegramHtml("[click here](https://example.com)");
 81→    expect(result).toBe('<a href="https://example.com">click here</a>');
 82→  });
 83→
 84→  it("escapes HTML in regular text", () => {
 85→    const result = markdownToTelegramHtml("a < b & c > d");
 86→    expect(result).toBe("a &lt; b &amp; c &gt; d");
 87→  });
 88→
 89→  it("does NOT escape HTML inside code blocks", () => {
 90→    const result = markdownToTelegramHtml("```\nif (a < b) {}\n```");
 91→    expect(result).toContain("&lt;");
 92→    expect(result).toContain("<pre>");
 93→  });
 94→
 95→  it("does NOT escape HTML inside inline code", () => {
 96→    const result = markdownToTelegramHtml("use `a < b`");
 97→    expect(result).toContain("<code>");
 98→    expect(result).toContain("&lt;");
 99→  });
100→
101→  it("handles empty string", () => {
102→    expect(markdownToTelegramHtml("")).toBe("");
103→  });
104→
105→  it("handles plain text without markdown", () => {
106→    expect(markdownToTelegramHtml("hello world")).toBe("hello world");
107→  });
108→
109→  it("handles multiple code blocks", () => {
110→    const md = "```js\nconst a = 1\n```\ntext\n```py\nprint(1)\n```";
111→    const result = markdownToTelegramHtml(md);
112→    expect(result).toContain("language-js");
113→    expect(result).toContain("language-py");
114→  });
115→
116→  it("preserves newlines in code blocks", () => {
117→    const result = markdownToTelegramHtml("```\nline1\nline2\n```");
118→    expect(result).toContain("line1\nline2");
119→  });
120→});
